<script lang="ts">  import type { TalkItem } from '../utils/postsFetcher';  import SvelteLightbox from './SvelteLightbox.svelte';  import TalkShareModal from './TalkShareModal.svelte';  import PageViews from './PageViews.svelte';  export let talk: TalkItem;  let isLightboxOpen = false;  let lightboxImages: string[] = [];  let lightboxInitialIndex = 0;  let showShare = false;  function openShare() {    showShare = true;    document.body.style.overflow = 'hidden';  }  function closeShare() {    showShare = false;    document.body.style.overflow = '';  }  function formatMarkdown(text: string): string {    if (!text) return "";    // Replace markdown bold tags    let html = text.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');    // Replace markdown link tags    html = html.replace(/\[(.*?)\]\((.*?)\)/g, '<a class="text-[#0ea5e9] font-bold hover:underline" href="$2" target="_blank" rel="noopener noreferrer">$1</a>');    return html.split('\n\n').map(p => `<p class="mb-3.5 leading-relaxed break-words">${p.replace(/\n/g, '<br/>')}</p>`).join('');  }  function extractImages(content: string): string[] {    const imageRegex = /!\[.*?\]\((.*?)\)/g;    return Array.from(content.matchAll(imageRegex)).map((m) => m[1]);  }  function getContentWithoutImages(content: string): string {    return content.replace(/!\[.*?\]\((.*?)\)/g, '').trim();  }  function openLightbox(imagesList: string[], index: number, e: Event) {    e.stopPropagation();    lightboxImages = imagesList;    lightboxInitialIndex = index;    isLightboxOpen = true;  }  $: images = extractImages(talk.content);  $: textOnly = getContentWithoutImages(talk.content);</script><div class="max-w-[800px] mx-auto w-full space-y-6">  <!-- Back button -->  <div class="mb-6 flex justify-start select-none animate-card-entrance opacity-0">     <a href="/talks" class="px-3 py-1.5 border-3 border-[#0284c7] bg-white dark:bg-slate-700 text-[#0284c7] dark:text-slate-200 flex items-center gap-1.5 hover:bg-[#0ea5e9] hover:text-white tran