ext-[#0284c7] text-lg">{talk.title}</h3>        </div>      {/if}            {#if textOnly}        <div class="prose prose-lg max-w-none text-slate-755 dark:text-slate-300 leading-relaxed font-medium">          {@html formatMarkdown(textOnly)}        </div>      {/if}      <!-- Nine-grid Image Gallery -->      {#if images.length > 0}        <div class="mt-4 grid gap-2 {images.length === 1 ? 'grid-cols-1 max-w-sm' : images.length === 2 || images.length === 4 ? 'grid-cols-2 max-w-xs' : 'grid-cols-3 max-w-md'}">          {#each images as src, idx}            <!-- svelte-ignore a11y-click-events-have-key-events -->            <div               class="w-full overflow-hidden rounded-sm border-2 border-[#0284c7] hover:border-[#f59e0b] shadow-[2px_2px_0px_0px_rgba(2,132,199,0.15)] hover:shadow-[3px_3px_0px_0px_#0284c7] transition-all cursor-pointer bg-slate-50 relative {images.length === 1 ? 'aspect-video sm:aspect-[4/3] max-h-80' : 'aspect-square'}"              on:click={(e) => openLightbox(images, idx, e)}            >              <img src={src} alt="talk detail graphic asset" class="w-full h-full object-cover transition-transform duration-550 hover:scale-[1.06]" loading="lazy" />            </div>          {/each}        </div>      {/if}      <!-- Bottom Metadata: Location, Weather, Device -->      {#if talk.location || talk.weather || talk.device}        <div class="mt-4 flex flex-wrap gap-3 items-center text-xs font-bold text-slate-500 dark:text-slate-400 select-none border-t border-dashed border-slate-100 dark:border-slate-700 pt-3">          {#if talk.location}            <span class="flex items-center gap-1 hover:text-[#0284c7] transition-colors"><span>рџ“Ќ</span> {talk.location}</span>          {/if}          {#if talk.weather}            <span class="flex items-center gap-1 hover:text-[#0284c7] transition-colors"><span>в›?/span> {talk.weather}</span>          {/if}          {#if talk.device}            <span class="flex items-center gap-1 hover:text-[#0284c7] 