ne" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2.5">    <path stroke-linecap="round" stroke-linejoin="round" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />  </svg></button>{#if showShare}  {@const images = extractImages(talk.content)}  {@const textOnly = getContentWithoutImages(talk.content)}  <TalkShareModal    talkTitle={talk.title || 'ж—ҐеёёеЉЁжЂ?}    talkContent={textOnly}    talkUrl={`${window.location.origin}/talk/${talk.slug}`}    talkImage={images[0] || ''}    show={true}    on:close={closeShare}  />{/if}{#if isLightboxOpen}  <SvelteLightbox images={lightboxImages} initialIndex={lightboxInitialIndex} onClose={() => isLightboxOpen = false} />{/if}